 using ModelContextProtocol.Server;

 /// <summary>
 /// MCP tools that wrap the JSONPlaceholder REST API.
 /// Uses constructor injection — the SDK resolves HttpClient and ILogger via DI
 /// and does NOT expose them in the tool schema. Only [Description] parameters
 /// are visible to the LLM.
 /// </summary>
 [McpServerToolType]
 public class JsonPlaceholderTools(IHttpClientFactory httpClientFactory, ILogger<JsonPlaceholderTools> logger)
 {
     private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

     [McpServerTool(ReadOnly = true), Description("Get a post by its ID from the JSONPlaceholder API.")]
     public async Task<string> GetPost(
         [Description("The numeric ID of the post (1-100)")] int postId,
         CancellationToken cancellationToken = default)
     {
         logger.LogInformation("Fetching post {PostId}", postId);
         var client = httpClientFactory.CreateClient("jsonplaceholder");
         var post = await client.GetStringAsync($"/posts/{postId}", cancellationToken);
         return post;
     }

     [McpServerTool(ReadOnly = true), Description("List posts, optionally filtered by user ID.")]
     public async Task<string> ListPosts(
         [Description("Filter posts by this user ID. Omit to list all posts.")] int? userId = null,
         CancellationToken cancellationToken = default)
     {
         var client = httpClientFactory.CreateClient("jsonplaceholder");
         var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
         logger.LogInformation("Listing posts from {Url}", url);
         var posts = await client.GetStringAsync(url, cancellationToken);
         return posts;
